// Verify /api/weather returns 400 when lat/lon are missing — caught by schema validation
async function testWeatherMissingParams() {
  const res = await fetch('http://localhost:3001/api/weather');
  assertEquals(res.status, 400);
  const body = await res.json();
  // Route schema validation returns this shape
  assertEquals(body.error, 'Validation failed');
  assert(body.details.length > 0, 'Should include validation detail messages');
}
